class Solution {
public:
    string smallestEquivalentString(string s1, string s2, string baseStr) {
        vector<int> parent(26);
        for (int i = 0; i < 26; i++) {
            parent[i] = i;
        }

        for (int i = 0; i < s1.size(); i++) {
            int x = find(parent, s1[i] - 'a');
            int y = find(parent, s2[i] - 'a');
            if (x > y) {
                parent[x] = y;
            } else if (x < y) {
                parent[y] = x;
            }
        }

        string res = "";
        for (char c : baseStr) {
            res += 'a' + find(parent, c - 'a');
        }
        return res;
    }

    int find(vector<int>& parent, int x) {
        if (parent[x] != x) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }
};
